import React from 'react'
import c from './add.module.scss'
import { Icons } from '../../assets/icons'
import { API } from '../../api'

const emptyRow = {
  name: '',
  quantity: '',
  price: '',
  category: '',
  price_seller: '',
  code: '',
  unit: 'шт',
  fixed_quantity: ''
}

const AddStock = ({ setActive }) => {
  const [count, setCount] = React.useState(1)
  const [categories, setCategories] = React.useState([])
  const [data, setData] = React.useState([emptyRow])

  /* ---------- helpers ---------------------------------------------------- */

  const handleChange = (index, field, value) => {
    setData(prev =>
      prev.map((row, i) => {
        if (i !== index) return row

        // при первом вводе quantity фиксируем fixed_quantity
        if (field === 'quantity') {
          return {
            ...row,
            quantity: value,
            fixed_quantity: row.fixed_quantity || value
          }
        }

        return { ...row, [field]: value }
      })
    )
  }

  const handleAddForm = () => {
    setCount(prev => prev + 1)
    setData(prev => [...prev, emptyRow])
  }

  const handleSave = () => {
    const payload = data.map(item => ({
      ...item,
      // страховка: если юзер стёр quantity, но fixed уже есть
      fixed_quantity: item.fixed_quantity || item.quantity,
      // числа → числа
      quantity: +item.quantity || 0,
      price: +item.price || 0,
      price_seller: +item.price_seller || 0,
      category_id: item.category || null          // backend ждёт *_id
    }))

    API.postStock(payload)
      .then(res => {
        if (res.status === 201 || res.status === 200) {
          setActive(false)
          window.location.reload()
        }
      })
      .catch(err => {
        console.error('Ошибка при сохранении товара:', err)
      })
  }

  /* ---------- fetch categories ------------------------------------------- */

  React.useEffect(() => {
    API.getCategories()
      .then(res => setCategories(res.data))
      .catch(err => console.error('Не удалось загрузить категории:', err))
  }, [])

  /* ---------- render ----------------------------------------------------- */

  return (
    <div className={c.addExpense}>
      <div className={c.addExpense__header}>
        <h2>Добавление товара</h2>
      </div>

      {Array.from({ length: count }).map((_, index) => (
        <div key={index} className={c.addExpense__form}>
          {/* Код */}
          <div className={c.addExpense__form__item}>
            <label htmlFor={`code-${index}`}>Код товара</label>
            <input
              type="text"
              id={`code-${index}`}
              placeholder="Код товара"
              value={data[index].code}
              onChange={e => handleChange(index, 'code', e.target.value)}
            />
          </div>

          {/* Наименование */}
          <div className={c.addExpense__form__item}>
            <label htmlFor={`name-${index}`}>Наименование товара</label>
            <input
              type="text"
              id={`name-${index}`}
              placeholder="Введите наименование"
              value={data[index].name}
              onChange={e => handleChange(index, 'name', e.target.value)}
            />
          </div>

          {/* Категория */}
          <div className={c.addExpense__form__item}>
            <label htmlFor={`category-${index}`}>Категория</label>
            <select
              id={`category-${index}`}
              value={data[index].category}
              onChange={e => handleChange(index, 'category', e.target.value)}
            >
              <option value="">‒ выберите ‒</option>
              {categories.map(cat => (
                <option key={cat.id} value={cat.id}>
                  {cat.name}
                </option>
              ))}
            </select>
          </div>

          {/* Кол-во */}
          <div className={c.addExpense__form__item}>
            <label htmlFor={`quantity-${index}`}>Количество</label>
            <input
              type="number"
              id={`quantity-${index}`}
              placeholder="Введите количество"
              value={data[index].quantity}
              onChange={e => handleChange(index, 'quantity', e.target.value)}
            />
          </div>

          {/* Цена поставщика */}
          <div className={c.addExpense__form__item}>
            <label htmlFor={`seller-${index}`}>Цена поставщика</label>
            <input
              type="number"
              id={`seller-${index}`}
              placeholder="Введите цену поставщика"
              value={data[index].price_seller}
              onChange={e => handleChange(index, 'price_seller', e.target.value)}
            />
          </div>

          {/* Цена продажи */}
          <div className={c.addExpense__form__item}>
            <label htmlFor={`price-${index}`}>Цена продажи</label>
            <input
              type="number"
              id={`price-${index}`}
              placeholder="Введите цену продажи"
              value={data[index].price}
              onChange={e => handleChange(index, 'price', e.target.value)}
            />
          </div>
        </div>
      ))}

      <button onClick={handleAddForm}>
        <img src={Icons.plus} alt="plus" />
        Добавить ещё
      </button>

      <div className={c.res}>
        <button onClick={() => setActive(false)}>Отменить</button>
        <button onClick={handleSave}>
          <img src={Icons.addGreen} alt="add" />
          Сохранить
        </button>
      </div>
    </div>
  )
}

export default AddStock
